import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns
from sklearn.model_selection import GridSearchCV
from sklearn.neighbors import KNeighborsClassifier

# Define the parameter grid
param_grid = {
    'n_neighbors': range(1, 21)
}

# Initialize the KNN model
# We explicitly set the metric to 'euclidean' (p=2) and weights to 'uniform'
knn = KNeighborsClassifier(metric='euclidean', weights='uniform')

# Set up GridSearchCV
grid_search = GridSearchCV(estimator=knn, param_grid=param_grid, cv=5, scoring='accuracy', n_jobs=-1)

# Train on the scaled training set
grid_search.fit(X_train, y_train)

# Extract results for plotting
results = pd.DataFrame(grid_search.cv_results_)
results['k'] = results['param_n_neighbors']
results['accuracy'] = results['mean_test_score']

"""Plot the **resulte**"""

# Plot Accuracy vs. K (Single Line)
plt.figure(figsize=(10, 6))
sns.lineplot(data=results, x='k', y='accuracy', marker='o', color='b')

plt.title('KNN Accuracy vs. K Value (Euclidean Distance)')
plt.xlabel('K (Number of Neighbors)')
plt.ylabel('Mean CV Accuracy')
plt.grid(True)
plt.xticks(range(1, 21))
plt.show()

# 7. Print the best K found
print(f"Best K: {grid_search.best_params_['n_neighbors']}")
print(f"Best Cross-Validation Accuracy: {grid_search.best_score_:.4f}")

# Evaluate on Test Set
best_model = grid_search.best_estimator_
print(f"Final Test Accuracy: {best_model.score(X_test, y_test):.4f}")

"""# **Logistic Regression**"""

import pandas as pd
from sklearn.linear_model import LogisticRegressionCV, LogisticRegression

# Define the models
c_values = [0.01, 0.1, 1, 10, 100]

# Standard logistic regression _ L2 , C=1.0.
lr = LogisticRegression()

# L1 Regularization with CV (Lasso)
# The model will test 5 different values for C automatically
lr_l1_cv = LogisticRegressionCV(Cs=c_values, cv=5, penalty='l1', solver='liblinear', random_state=42)

# L2 Regularization with CV (Ridge)
lr_l2_cv = LogisticRegressionCV(Cs=c_values, cv=5, penalty='l2', solver='liblinear', random_state=42)

# Train the models using Cross-Validation
print("Training models with Cross-Validation...")
lr.fit(X_train, y_train)
lr_l1_cv.fit(X_train, y_train)
lr_l2_cv.fit(X_train, y_train)

print(f"Best C for L1: {lr_l1_cv.C_[0]:.4f}")
print(f"Best C for L2: {lr_l2_cv.C_[0]:.4f}")

# Compare Coefficients

coeff_labels = ['Lr (Regular)', 'L1 (Optimized)', 'L2 (Optimized)']
coeff_models = [lr, lr_l1_cv, lr_l2_cv]

coefficients = []

# Get feature names from the training set
feature_names = X_train.columns.tolist()

for lab, mod in zip(coeff_labels, coeff_models):
    coeffs = mod.coef_

    # Create a DataFrame for the current model
    # coeffs.T transposes the array to a vertical column
    # We use the feature names as the index (rows)
    df_temp = pd.DataFrame(coeffs.T, columns=[lab], index=feature_names)

    coefficients.append(df_temp)

# Concatenate all columns into a single DataFrame
coefficients_df = pd.concat(coefficients, axis=1)

print("\n--- Coefficients Comparison ---")
display(coefficients_df)

import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

# Define lists of model names and the actual trained model objects from the previous step
