from sklearn.metrics import precision_recall_fscore_support as score
from sklearn.metrics import confusion_matrix, accuracy_score, roc_auc_score

# model_names = ['Lr (Regular)', 'L1 (Lasso)', 'L2 (Ridge)']
# trained_models = [lr, lr_l1_cv, lr_l2_cv]

metrics_list = []
cm_dict = {}

# -----------------THRESHOLDS range---------
#THRESHOLD = 0.5
THRESHOLD = 0.35
#THRESHOLD = 0.4

# Loop through each trained model
for name, model in zip(model_names, trained_models):
    # Predict on the test set
    y_probs = model.predict_proba(X_test)[:, 1]
    y_pred = (y_probs >= THRESHOLD).astype(int)

    # If want just predict with 0.5
    #y_pred = model.predict(X_test)

    # Calculate Precision, Recall, and F-score
    # average='weighted' accounts for any class imbalance
    precision, recall, fscore, _ = score(y_test, y_pred, average='weighted')

    # Calculate Accuracy
    accuracy = accuracy_score(y_test, y_pred)

    # Calculate ROC-AUC
    auc = roc_auc_score(y_test, y_probs)

    # Store the Confusion Matrix for later display
    cm_dict[name] = confusion_matrix(y_test, y_pred)

    # Append the results to the list
    metrics_list.append(pd.Series({
        'Precision': precision,
        'Recall': recall,
        'F1-Score': fscore,
        'Accuracy': accuracy,
        'AUC': auc
    }, name=name))

# Concatenate all results into a final DataFrame
metrics_df = pd.concat(metrics_list, axis=1)

print("\n--- Final Performance Metrics ---")
display(metrics_df)

