"""# **Decision tree**"""

from sklearn.tree import DecisionTreeClassifier
from sklearn.model_selection import GridSearchCV
import pandas as pd
import matplotlib.pyplot as plt
from sklearn.metrics import roc_curve, auc, accuracy_score, roc_auc_score
from sklearn.metrics import precision_score, recall_score, f1_score

# --- Helper Function for Metrics Table ---
def measure_error(y_true, y_pred, label):
    return pd.Series({
        'accuracy': accuracy_score(y_true, y_pred),
        'precision': precision_score(y_true, y_pred, average='weighted'),
        'recall': recall_score(y_true, y_pred, average='weighted'),
        'f1': f1_score(y_true, y_pred, average='weighted')
    }, name=label)

"""**Full Decision Tree**"""

# Fit on traning
dt_full = DecisionTreeClassifier(random_state=42)
dt_full.fit(X_train, y_train)
dt_full.tree_.node_count, dt_full.tree_.max_depth

# Predict on Train and Test
y_train_pred_full = dt_full.predict(X_train)
y_test_pred_full = dt_full.predict(X_test)

# Create the table
full_tree_metrics = pd.concat([measure_error(y_train, y_train_pred_full, 'train'),
                               measure_error(y_test, y_test_pred_full, 'test')],
                              axis=1)

print("Full Decision Tree Performance---")
display(full_tree_metrics)

"""**Shallow Decision Tree**"""

# Traning step
dt_shallow = DecisionTreeClassifier(max_depth=3, random_state=42)
dt_shallow.fit(X_train, y_train)
dt_shallow.tree_.node_count, dt_shallow.tree_.max_depth

# Predict on Train and Test
y_train_pred_shallow = dt_shallow.predict(X_train)
y_test_pred_shallow = dt_shallow.predict(X_test)

# Create the table
shallow_tree_metrics = pd.concat([measure_error(y_train, y_train_pred_shallow, 'train'),
                                  measure_error(y_test, y_test_pred_shallow, 'test')],
                                 axis=1)

print("\n--Shallow Decision Tree Performance (Max Depth = 3) ---")
display(shallow_tree_metrics)

"""**Finding the Optimal Tree (Grid Search CV)**"""

# Try 1-12 depth
param_grid = {
    'max_depth': range(1, dt_full.tree_.max_depth + 1),
    'min_samples_leaf': [1, 5, 10, 20],
    'criterion': ['gini', 'entropy']
}

# DO 5 divisions
grid_dt = GridSearchCV(
    DecisionTreeClassifier(random_state=42),
    param_grid,
    cv=5,
    scoring='accuracy',
    n_jobs=-1
)

# Fit on train
grid_dt.fit(X_train, y_train)
best_dt = grid_dt.best_estimator_

print(f"Best Params: {grid_dt.best_params_}")
print(f"Best CV Score: {grid_dt.best_score_:.4f}")

"""**Final Metrics for Best Tree**"""

# Predict on Train and Test
y_train_pred_opt = best_dt.predict(X_train)
y_test_pred_opt = best_dt.predict(X_test)

# Create the table
optimized_tree_metrics = pd.concat([measure_error(y_train, y_train_pred_opt, 'train'),
                                    measure_error(y_test, y_test_pred_opt, 'test')],
                                   axis=1)

