from sklearn.pipeline import Pipeline
from sklearn.cluster import KMeans
from sklearn.decomposition import PCA
from sklearn.model_selection import StratifiedShuffleSplit
from sklearn.metrics import accuracy_score
import numpy as np
import matplotlib.pyplot as plt
import seaborn as sns

# Using X_train and y_train as the base data
X = X_train
y = y_train

# Define the StratifiedShuffleSplit
sss = StratifiedShuffleSplit(n_splits=5, test_size=0.3, random_state=42)

def get_avg_score(n):
    # Build the Pipeline
    # Removed StandardScaler as the data is already scaled. Using KMeans
    pipe = [
        ('pca', PCA(n_components=n)),
        ('kmeans', KMeans(n_clusters=2, random_state=42))
    ]
    pipe = Pipeline(pipe)

    scores = []

    # Split and evaluate loop using the global SSS object
    for train_index, test_index in sss.split(X, y):
        X_train_fold, X_test_fold = X.iloc[train_index], X.iloc[test_index]
        y_test_fold = y.iloc[test_index]

        # Train the pipeline (KMeans fits)
        pipe.fit(X_train_fold)

        # Predict clusters
        y_pred = pipe.predict(X_test_fold)

        # KMeans Accuracy
        acc = accuracy_score(y_test_fold, y_pred)
        scores.append(max(acc, 1 - acc))

    return np.mean(scores)

ns = [2, 3, 4, 5, 6, 7]
score_list_kmeans = [get_avg_score(n) for n in ns]

sns.set_context('talk')
ax = plt.axes()

ax.plot(ns, score_list_kmeans)

ax.set(xlabel='Number of Dimensions',
       ylabel='Average Accuracy',
       title='K-Means Accuracy vs Number of Dimensions')

ax.grid(True)

