import matplotlib.pyplot as plt
import seaborn as sns
from sklearn.metrics import confusion_matrix

# Generate predictions using the specific Threshold (0.35)
# THRESHOLD = 0.5
# THRESHOLD = 0.6
THRESHOLD = 0.35

# Get probabilities for the positive class (Diabetes)
y_probs = best_dt.predict_proba(X_test)[:, 1]

# Apply the threshold to create binary predictions (0 or 1)
y_pred_opt = (y_probs >= THRESHOLD).astype(int)

cm_tree = confusion_matrix(y_test, y_pred_opt)

