"""# **Plot the ROC graph**"""

# Plot the roc graph
from sklearn.metrics import roc_curve, auc
import matplotlib.pyplot as plt

# Prepare lists for the ROC plot
# We add to KNN, Logistic, Naive Bayes the Decision Tree model
all_names = all_names + ['Decision Tree']
all_models = all_models + [best_dt]

plt.figure(figsize=(10, 8))

# Loop through all models to calculate and plot ROC curves
for name, model in zip(all_names, all_models):
    # Get predicted probabilities for the positive class (Diabetes)
    # Most sklearn classifiers have predict_proba
    y_probs = model.predict_proba(X_test)[:, 1]

    # Calculate False Positive Rate and True Positive Rate
    fpr, tpr, _ = roc_curve(y_test, y_probs)

    # Calculate the Area Under the Curve (AUC)
    roc_auc = auc(fpr, tpr)

    # Plot the ROC curve for this specific model
    plt.plot(fpr, tpr, lw=2, label=f'{name} (AUC = {roc_auc:.4f})')

# Plot the random guess line (diagonal)
plt.plot([0, 1], [0, 1], color='gray', lw=1, linestyle='--', label='Random Guess')

# Graph Aesthetics
plt.xlim([0.0, 1.0])
plt.ylim([0.0, 1.05])
plt.xlabel('False Positive Rate (1 - Specificity)')
plt.ylabel('True Positive Rate (Sensitivity)')
plt.title('Final Comparison: ROC Curves - after fix')
plt.legend(loc="lower right")
plt.grid(alpha=0.3)

plt.show()

"""# **Unsupervised learning + PCA**

Perform PCA with n_components ranging from 1 to 6 and Analyze the results
"""

#data.head()
import pandas as pd
import numpy as np
import matplotlib.pyplot as plt
import seaborn as sns
from sklearn.decomposition import PCA
from sklearn.pipeline import Pipeline
from sklearn.cluster import KMeans

# concatenate the scaled data to get a full picture for visualization
X_full = pd.concat([X_train, X_test])
y_full = pd.concat([y_train, y_test])

print("Performing PCA Analysis on FULL Data (Exploration) ---")

pca_list = list()
feature_weight_list = list()

for n in range(1, 7):
  # Create and fit the model
  PCAmod = PCA(n_components=n)
  PCAmod.fit(X_full)

  # Store the model and variance
  pca_list.append(pd.Series({'n':n, 'model':PCAmod,
                            'var': PCAmod.explained_variance_ratio_.sum()}))
  # Calculate feature importance
  abs_feature_values = np.abs(PCAmod.components_).sum(axis=0)
  feature_weight_list.append(pd.DataFrame({'n': n,
        'features': X_full.columns,
        'values': abs_feature_values / abs_feature_values.sum()
    }))

pca_df = pd.concat(pca_list, axis=1).T.set_index('n')
pca_df

"""**Table of feature importances for each data column.**"""

features_df = (pd.concat(feature_weight_list)
               .pivot(index='n', columns='features', values='values'))
features_df

""" **A Plot of explained variances.**"""

sns.set_context('talk')

ax = pca_df['var'].plot(kind='bar')

ax.set(xlabel='Number of dimensions',
       ylabel='Percent explained variance',
       title='Explained Variance vs Dimensions');

"""# **Feature importances.**"""

ax = features_df.plot(kind='bar')

ax.set(
    xlabel='Number of dimensions',
    ylabel='Relative importance',
    title='Feature importance vs Dimensions'
)

ax.legend(loc='center left', bbox_to_anchor=(1, 0.5))

